/* Hex Color Codes

Black - 151A1F
Dark Grey - 263038
Grey - 50555C
Neon Orange - F98331
Orange - FEAC27
Yellow - FFC107


*/

/* Set box colors for box with id="Info_Box" - grey, Sub_Info_Box is for layered boxes, so no height */

#Info_Box {
	/* height: 240px; 18em;*/
	height: 18em;
	background: #151A1F;
	border-style: hidden;
} 

#v2_Info_Box {
	height: 140px;
	background: #151A1F;
	border-style: hidden;
	margin-top: 2px;
	margin-left: 0px; 
	margin-right: 0px; 
	margin-bottom:0px;
	padding:-10px
} 

#Sub_Info_Box_v2 {
	height: 50px;
	background: #50555C;
	border-style: hidden;
	margin-top: 0px;
	margin-left: 0px; 
	margin-right: 0px; 
	margin-bottom:20px;
	padding:-10px
} 


/* Set box colors for box with id="Donation_Box" - grey */

#Donation_Box {
	background:#50555C;
	/* height: 80px; */
	height: 6em;
}

/* vertical center icons for boxes    */
#Icon_Vertical_Middle {
  margin-top: 15px ;
  color: #F98331; 
  font-size: 72px;
}
#Icon_Donation {
  color: #F98331; 
  font-size: 28px;
}


/* Set default color for all boxes & turn off headers */
.box {
  border-style: hidden;
} 
.box-header{
  display: none
}

/* set main header - loho to orange */
.skin-blue .main-header .logo {
  background-color: #151A1F;
  color: #000000;
  padding: 0px; 
} .header_img {
  margin-left: -90px;
}
.skin-blue .main-header .logo:hover {
  background-color: #151A1F;
}
 /* navbar (rest of the header) */
.skin-blue .main-header .navbar {
  background-image: linear-gradient(to right, #151A1F, #263038);
}   

/* set main sidebar to orange */
.skin-blue .main-sidebar {
  background-color: #50555C;
}

/* body */
.content-wrapper {
  background-color: #FFFFFF;
}
